def __getattr__(name: str) -> Any:
    lazy_export = _LAZY_EXPORTS.get(name)
    if lazy_export is not None:
        module_name, attr_name = lazy_export
        value = getattr(import_module(module_name), attr_name)
        globals()[name] = value
        return value
    if name in {"hosts", "integrations", "sdk"}:
        return import_module(f"lemoncrow.gateway.{name}")
    if name in {"LemonCrowClient", "LocalClient", "MCPClient", "RemoteClient"}:
        mod = import_module("lemoncrow.gateway.sdk")
        return getattr(mod, name)
    if name == "storage":
        return import_module("lemoncrow.infra.storage")
    if name == "service":
        return import_module("lemoncrow.core.service")
    raise AttributeError(f"module {__name__!r} has no attribute {name!r}")

