def _collect_doc_paths(roots: list[Path]) -> list[Path]:
    out: list[Path] = []
    seen: set[str] = set()
    for root in roots:
        if root.is_file() and root.suffix.lower() in {".md", ".markdown"}:
            key = str(root.resolve())
            if key not in seen:
                seen.add(key)
                out.append(root)
        elif root.is_dir():
            for md in sorted(root.rglob("*.md")):
                key = str(md.resolve())
                if key not in seen:
                    seen.add(key)
                    out.append(md)
    return out

