def ancestors(graph: DiGraph, source: str) -> set[str]:
    """All nodes with a directed path leading *to* ``source`` (reversed BFS)."""
    visited: set[str] = set()
    queue: deque[str] = deque([source])
    while queue:
        node = queue.popleft()
        for pred in graph._in.get(node, {}):
            if pred not in visited:
                visited.add(pred)
                queue.append(pred)
    return visited

